const d = $input.item.json || {};
const wf = d.workflow || {};
const ex = d.execution || {};
const err = ex.error || {};

const wfName = wf.name || '(desconocido)';
const node = ex.lastNodeExecuted || '(desconocido)';
const mode = ex.mode || '';
const url = ex.url || '';
const msg = err.message || err.description || '(sin mensaje)';
const stack = (err.stack || '').split('\n').slice(0, 6).join('\n');

const subject = '[n8n] Falló: ' + wfName + ' → ' + node;

const text = [
  'Un workflow de n8n ha fallado.',
  '',
  'Workflow:   ' + wfName,
  'Nodo:       ' + node,
  'Modo:       ' + mode,
  'Error:      ' + msg,
  '',
  'Traza:',
  stack,
  '',
  url ? ('Ver ejecución: ' + url) : ''
].join('\n');

return [{ json: { subject: subject, text: text } }];
